/**
 * @summary Monthly profit/loss report
 */
export const getGetProfitLossReportUrl = (
  params?: GetProfitLossReportParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/profit-loss?${stringifiedParams}`
    : `/api/reports/profit-loss`;
};

export const getProfitLossReport = async (
  params?: GetProfitLossReportParams,
  options?: RequestInit,
): Promise<ProfitLossMonth[]> => {
  return customFetch<ProfitLossMonth[]>(getGetProfitLossReportUrl(params), {
    ...options,
    method: "GET",
  });
};

